// src/data/fuel-usage-calculator.ts
// Fuel Usage Calculator — 582 real machines across 53 equipment types, 51 manufacturers
// Extracted from Jonathan Jackson's plant database, April 2026

export interface PlantMachine {
  id: number;
  make: string;
  model: string;
  type: string;
  size: number;
  engineKw: number;
  fuel100: number;
  fuel75: number;
  fuel50: number;
  fuel25: number;
  idle: number;
  fuelType: string;
  emissionStage: string;
  isGeneric?: boolean;
  basedOn?: number;
}

export type DutyCycle = '100' | '75' | '50' | '25';
export type DutyCycleKey = 'fuel100' | 'fuel75' | 'fuel50' | 'fuel25';

export const DUTY_CYCLES: { id: DutyCycle; key: DutyCycleKey; label: string; description: string }[] = [
  { id: '100', key: 'fuel100', label: '100%', description: 'Full load — maximum continuous output' },
  { id: '75', key: 'fuel75', label: '75%', description: 'Heavy duty — typical hard digging or loaded haul' },
  { id: '50', key: 'fuel50', label: '50%', description: 'Medium duty — mixed work with some idle' },
  { id: '25', key: 'fuel25', label: '25%', description: 'Light duty — intermittent use or mostly idle' },
];

export function getFuelRate(machine: PlantMachine, duty: DutyCycle): number {
  switch (duty) {
    case '100': return machine.fuel100;
    case '75': return machine.fuel75;
    case '50': return machine.fuel50;
    case '25': return machine.fuel25;
  }
}

// UK Gov GHG Conversion Factors 2024 (Scope 1 / direct combustion, fossil CO₂ only).
// Both diesel and HVO factors are on the same basis ("in-scope") so the comparison is consistent.
// Users wanting WTW totals (Scope 1+3, lifecycle) should refer to GOV.UK: diesel ≈ 3.13, HVO ≈ 0.50 kgCO₂e/L.
export const FUEL_CARBON_FACTORS: Record<string, number> = {
  'Diesel': 2.68, // 100% mineral diesel direct combustion (2024 GOV.UK = 2.66; rounded)
  'Electric': 0,
  'Diesel (Hybrid)': 2.68,
  'HVO': 0.036, // Biodiesel HVO direct combustion, in-scope (2024 GOV.UK)
};

export const DEFAULT_FUEL_PRICE = 1.30; // £/litre diesel (UK approx 2025)


